mapper.select:
SELECT C.RN , C.FILE_NO , C.FILE_NM , C.FILE_NM_DTL , C.EXT FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.MAP_NO ASC) AS RN , A.POST_NO , A.FILE_NO , B.FILE_NM , B.FILE_NM_DTL , SUBSTRING_INDEX(B.FILE_NM_DTL, '.', -1) AS EXT FROM FILE_POST_MAPPER A JOIN FILE_MASTER B ON A.FILE_NO = B.FILE_NO WHERE 1=1
AND A.POST_NO = #{postNo}
) C WHERE 1=1 ORDER BY C.RN

mapper.insert:
INSERT INTO POST_MASTER
(
	BOARD_NO
  , TITLE
  , CONTENT
  , VIEW_CNT
  , REG_NO
  , REG_DATE
  , UP_NO
  , UP_DATE
)
VALUES
(
	#{boardNo}
  , #{title}
  , #{content}
  , 0
  , #{regNo}
  , NOW()
  , #{upNo}
  , NOW()
)

mapper.update:
UPDATE
	POST_MASTER
SET
	TITLE = #{title}
  , CONTENT = #{content}
  
  	  , BOARD_NO = #{boardNo}
  
  , UP_NO = #{upNo}
  , UP_DATE = NOW()
WHERE
		1=1

	AND POST_NO = #{postNo}

UPDATE FILE_POST_MAPPER SET FILE_NO = ( SELECT MAX(FILE_NO) FROM FILE_MASTER ) , UP_NO = #{upNo} , UP_DATE = NOW() WHERE 1=1
AND POST_NO = #{postNo}
AND FILE_NO = #{fileNo}

mapper.select:
SELECT A.COMMENT_NO , A.POST_NO , A.CONTENT , A.REG_NO , B.USER_NM , DATE_FORMAT(A.REG_DATE, "%Y-%m-%d") AS FM_REG_DATE FROM COMMENT_MASTER A JOIN USER_MASTER B ON A.REG_NO = B.USER_IDX WHERE 1=1
AND A.POST_NO = #{postNo}
ORDER BY A.COMMENT_NO DESC

